from pathlib import Path
import re

def norm_text(path: str) -> str:
    return ' '.join(Path(path).read_text().split())

required = [
    '.planning/acceptance-matrix.md',
    '.planning/ship-verdict.md',
    '.planning/RELEASE_NOTES.md',
]
for rel in required:
    if not Path(rel).exists():
        raise SystemExit(f'missing required file: {rel}')

impl = Path('.planning/IMPLEMENTATION_NOTES.md').read_text()
if not re.search(r'^## Changes$', impl, re.M):
    raise SystemExit('missing literal ## Changes heading in IMPLEMENTATION_NOTES.md')

matrix = Path('.planning/acceptance-matrix.md').read_text()
reqs = re.findall(r'\| (REQ-\d{3}) \|', matrix)
if len(set(reqs)) != 28:
    raise SystemExit(f'expected 28 unique REQ rows, found {len(set(reqs))}')
for req in ['REQ-026', 'REQ-027', 'REQ-028']:
    row = next((line for line in matrix.splitlines() if f'| {req} |' in line), None)
    if not row or '| PASS |' not in row:
        raise SystemExit(f'{req} missing PASS row')

texts = {
    'website/src/pages/index.tsx': norm_text('website/src/pages/index.tsx'),
    'website/docusaurus.config.ts': norm_text('website/docusaurus.config.ts'),
    '.planning/RELEASE_NOTES.md': norm_text('.planning/RELEASE_NOTES.md'),
    '.planning/ship-verdict.md': norm_text('.planning/ship-verdict.md'),
    'README.md': norm_text('README.md'),
}
required_phrases = {
    'website/src/pages/index.tsx': [
        'reviewed, inspectable capability surface',
        'describe-only MCP endpoint that clients can inspect',
        'schemas and example payloads, not live execution',
    ],
    'website/docusaurus.config.ts': [
        'reviewed manifests, approved tool definitions, and a describe-only MCP surface',
    ],
    '.planning/RELEASE_NOTES.md': [
        'repo to reviewed manifest to approved tool definitions to inspectable describe-only MCP',
        'should not be described as a live execution engine, hosted platform, plugin ecosystem, runtime learning system, or shipped skill/agent generator',
    ],
    '.planning/ship-verdict.md': [
        'The previous QA turn correctly re-proved',
        'one specific promise: repo to reviewed manifest to approved tool definitions to a local describe-only MCP endpoint that clients can inspect',
        'No blocking issues were found.',
        'Human approval required before transitioning to `launch` phase',
    ],
}
for path, needles in required_phrases.items():
    for needle in needles:
        if needle not in texts[path]:
            raise SystemExit(f'missing phrase in {path}: {needle}')

for needle in ['MCP-ready']:
    if any(needle in texts[path] for path in ['website/src/pages/index.tsx', 'website/docusaurus.config.ts', '.planning/RELEASE_NOTES.md']):
        raise SystemExit(f'forbidden broad phrase still present in launch surface: {needle}')

if 'runtime learning' not in texts['README.md']:
    raise SystemExit('expected broader roadmap language missing from README; verifier assumptions stale')

print('qa ship package verifier passed')
